/* Structure to hold a file's name and counts for sorting */
struct file_result {
    char *name;
    struct counts cnts;
};

/* Comparison function for qsort - ASCIIbetical order by filename */
static int
cmp_results(const void *a, const void *b)
{
    const struct file_result *ra = a;
    const struct file_result *rb = b;
    return strcmp(ra->name, rb->name);
}

static int
do_count(char *input_files[], const int nfiles,
    const bool char_flag, const bool word_flag,
    const bool line_flag, const bool test_flag)
{
    (void)test_flag;

    int error_flag = 0;
    struct counts total = {0, 0, 0};
    int nresults = 0;

    /* Allocate memory for results */
    struct file_result *results = Malloc(nfiles * sizeof(*results));

    /* Process each file in input order */
    for (int i = 0; i < nfiles; i++) {
        FILE *fp = fopen(input_files[i], "r");
        if (fp == NULL) {
            app_error_fmt("cannot open file '%s'", input_files[i]);
            error_flag = 1;
            continue;
        }

        struct counts cnts = {0, 0, 0};
        int ch;
        bool in_word = false;
        bool read_error = false;

        while ((ch = fgetc(fp)) != EOF) {
            if (char_flag)
                cnts.chars++;
            if (line_flag && ch == '\n')
                cnts.lines++;
            if (word_flag) {
                if (isspace(ch)) {
                    in_word = false;
                } else {
                    if (!in_word) {
                        cnts.words++;
                        in_word = true;
                    }
                }
            }
        }

        /* Check for read error (as opposed to normal EOF) */
        if (ferror(fp)) {
            app_error_fmt("cannot read file '%s'", input_files[i]);
            error_flag = 1;
            read_error = true;
        }

        fclose(fp);

        if (read_error)
            continue;

        /* Store result for later sorting */
        results[nresults].name = input_files[i];
        results[nresults].cnts = cnts;
        nresults++;

        /* Accumulate totals */
        total.chars += cnts.chars;
        total.words += cnts.words;
        total.lines += cnts.lines;
    }

    /* Sort results ASCIIbetically by filename */
    qsort(results, nresults, sizeof(*results), cmp_results);

    /* Print sorted results */
    for (int i = 0; i < nresults; i++) {
        print_counts(stdout, &results[i].cnts, results[i].name,
            char_flag, word_flag, line_flag);
    }

    /* Print totals (always print all three counts) */
    print_counts(stdout, &total, "total", true, true, true);

    Free(results);

    return error_flag;
}

/* Allocate memory for results */
